import React, { useEffect, useRef } from 'react';

const VirtualKeyboard = ({ activeKey, isCorrect }) => {
  const lastProcessedKeyRef = useRef(null);
  const lastIsCorrectRef = useRef(null);

  // Finger mapping for highlighting
  const fingerMap = {
    // Left hand
    'q': 'left-pinky', 'a': 'left-pinky', 'z': 'left-pinky', '1': 'left-pinky',
    'w': 'left-ring', 's': 'left-ring', 'x': 'left-ring', '2': 'left-ring',
    'e': 'left-middle', 'd': 'left-middle', 'c': 'left-middle', '3': 'left-middle',
    'r': 'left-index', 'f': 'left-index', 'v': 'left-index', 't': 'left-index', 'g': 'left-index', 'b': 'left-index', '4': 'left-index', '5': 'left-index',

    // Right hand
    'y': 'right-index', 'h': 'right-index', 'n': 'right-index', 'u': 'right-index', 'j': 'right-index', 'm': 'right-index', '6': 'right-index', '7': 'right-index',
    'i': 'right-middle', 'k': 'right-middle', ',': 'right-middle', '8': 'right-middle',
    'o': 'right-ring', 'l': 'right-ring', '.': 'right-ring', '9': 'right-ring',
    'p': 'right-pinky', ';': 'right-pinky', "'": 'right-pinky', '/': 'right-pinky', '0': 'right-pinky', '-': 'right-pinky', '=': 'right-pinky', '[': 'right-pinky', ']': 'right-pinky',

    ' ': 'thumbs'
  };

  const fingerNames = {
    'left-pinky': 'Left Pinky',
    'left-ring': 'Left Ring',
    'left-middle': 'Left Middle',
    'left-index': 'Left Index',
    'right-index': 'Right Index',
    'right-middle': 'Right Middle',
    'right-ring': 'Right Ring',
    'right-pinky': 'Right Pinky',
    'thumbs': 'Thumbs'
  };

  const keyboardLayout = [
    ['1', '2', '3', '4', '5', '6', '7', '8', '9', '0', '-', '='],
    ['q', 'w', 'e', 'r', 't', 'y', 'u', 'i', 'o', 'p', '[', ']'],
    ['a', 's', 'd', 'f', 'g', 'h', 'j', 'k', 'l', ';', "'"],
    ['z', 'x', 'c', 'v', 'b', 'n', 'm', ',', '.', '/'],
    ['SPACE']
  ];

  // Play sound only when key changes and isCorrect is defined
  useEffect(() => {
    if (activeKey && isCorrect !== null && isCorrect !== undefined) {
      // Check if this is a new keystroke
      if (lastProcessedKeyRef.current !== activeKey || lastIsCorrectRef.current !== isCorrect) {
        lastProcessedKeyRef.current = activeKey;
        lastIsCorrectRef.current = isCorrect;

        if (isCorrect) {
          playCorrectSound();
        } else {
          playWrongSound();
        }
      }
    }
  }, [activeKey, isCorrect]);

  const playCorrectSound = () => {
    const audioContext = new (window.AudioContext || window.webkitAudioContext)();
    const oscillator = audioContext.createOscillator();
    const gainNode = audioContext.createGain();

    oscillator.connect(gainNode);
    gainNode.connect(audioContext.destination);

    oscillator.frequency.value = 800;
    oscillator.type = 'sine';

    gainNode.gain.setValueAtTime(0.08, audioContext.currentTime);
    gainNode.gain.exponentialRampToValueAtTime(0.01, audioContext.currentTime + 0.04);

    oscillator.start(audioContext.currentTime);
    oscillator.stop(audioContext.currentTime + 0.04);
  };

  const playWrongSound = () => {
    const audioContext = new (window.AudioContext || window.webkitAudioContext)();
    const oscillator = audioContext.createOscillator();
    const gainNode = audioContext.createGain();

    oscillator.connect(gainNode);
    gainNode.connect(audioContext.destination);

    oscillator.frequency.value = 300;
    oscillator.type = 'sine';

    gainNode.gain.setValueAtTime(0.06, audioContext.currentTime);
    gainNode.gain.exponentialRampToValueAtTime(0.01, audioContext.currentTime + 0.06);

    oscillator.start(audioContext.currentTime);
    oscillator.stop(audioContext.currentTime + 0.06);
  };

  const isKeyActive = (key) => {
    if (!activeKey) return false;

    if (key === 'SPACE' && activeKey === ' ') return true;

    return key.toLowerCase() === activeKey.toLowerCase();
  };

  const getFingerClass = (key) => {
    const normalizedKey = key === 'SPACE' ? ' ' : key.toLowerCase();
    return fingerMap[normalizedKey] || '';
  };

  const getCurrentFinger = () => {
    if (!activeKey) return '';
    const normalizedKey = activeKey === ' ' ? ' ' : activeKey.toLowerCase();
    return fingerMap[normalizedKey] || '';
  };

  const currentFinger = getCurrentFinger();
  const currentFingerName = fingerNames[currentFinger] || '';

  return (
    <div className="virtual-keyboard">
      {/* Hand Visualization */}
      <div className="hand-guidance">
        <div className="left-hand">
          <svg width="120" height="100" viewBox="0 0 120 100">
            <g className={`finger ${currentFinger === 'left-pinky' ? 'active-finger' : ''}`}>
              <rect x="10" y="20" width="15" height="60" rx="7" fill="#f0e6d2" stroke="#333" strokeWidth="1.5"/>
            </g>
            <g className={`finger ${currentFinger === 'left-ring' ? 'active-finger' : ''}`}>
              <rect x="30" y="10" width="15" height="70" rx="7" fill="#f0e6d2" stroke="#333" strokeWidth="1.5"/>
            </g>
            <g className={`finger ${currentFinger === 'left-middle' ? 'active-finger' : ''}`}>
              <rect x="50" y="5" width="15" height="75" rx="7" fill="#f0e6d2" stroke="#333" strokeWidth="1.5"/>
            </g>
            <g className={`finger ${currentFinger === 'left-index' ? 'active-finger' : ''}`}>
              <rect x="70" y="10" width="15" height="70" rx="7" fill="#f0e6d2" stroke="#333" strokeWidth="1.5"/>
            </g>
            <g className={`finger ${currentFinger === 'thumbs' ? 'active-finger' : ''}`}>
              <rect x="85" y="60" width="25" height="15" rx="7" fill="#f0e6d2" stroke="#333" strokeWidth="1.5"/>
            </g>
          </svg>
        </div>

        <div className="finger-instruction">
          {currentFingerName && (
            <div className="finger-name-box">
              Press: <strong>{activeKey === ' ' ? 'SPACE' : activeKey.toUpperCase()}</strong>
              <br />
              <span>Use: {currentFingerName}</span>
            </div>
          )}
        </div>

        <div className="right-hand">
          <svg width="120" height="100" viewBox="0 0 120 100">
            <g className={`finger ${currentFinger === 'thumbs' ? 'active-finger' : ''}`}>
              <rect x="10" y="60" width="25" height="15" rx="7" fill="#f0e6d2" stroke="#333" strokeWidth="1.5"/>
            </g>
            <g className={`finger ${currentFinger === 'right-index' ? 'active-finger' : ''}`}>
              <rect x="35" y="10" width="15" height="70" rx="7" fill="#f0e6d2" stroke="#333" strokeWidth="1.5"/>
            </g>
            <g className={`finger ${currentFinger === 'right-middle' ? 'active-finger' : ''}`}>
              <rect x="55" y="5" width="15" height="75" rx="7" fill="#f0e6d2" stroke="#333" strokeWidth="1.5"/>
            </g>
            <g className={`finger ${currentFinger === 'right-ring' ? 'active-finger' : ''}`}>
              <rect x="75" y="10" width="15" height="70" rx="7" fill="#f0e6d2" stroke="#333" strokeWidth="1.5"/>
            </g>
            <g className={`finger ${currentFinger === 'right-pinky' ? 'active-finger' : ''}`}>
              <rect x="95" y="20" width="15" height="60" rx="7" fill="#f0e6d2" stroke="#333" strokeWidth="1.5"/>
            </g>
          </svg>
        </div>
      </div>

      {/* Keyboard */}
      {keyboardLayout.map((row, rowIndex) => (
        <div key={rowIndex} className="keyboard-row">
          {row.map((key) => {
            const fingerClass = getFingerClass(key);
            const isActive = isKeyActive(key);

            return (
              <div
                key={key}
                className={`key ${key === 'SPACE' ? 'space' : ''} ${
                  isActive ? 'active' : ''
                } ${fingerClass}`}
              >
                {key === 'SPACE' ? 'Space' : key}
              </div>
            );
          })}
        </div>
      ))}
      <div style={{ textAlign: 'center', marginTop: '0.75rem', color: '#666', fontSize: '0.85rem' }}>
        <p>Keep your fingers on the home row: A S D F | J K L ;</p>
      </div>
    </div>
  );
};

export default VirtualKeyboard;
